/*
 * Virtual Memory Management Simulation
 * Demonstrates concepts used by hypervisors and VMs for memory virtualization
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

// Constants for memory management
#define PAGE_SIZE 4096 // 4KB pages (standard page size)
#define NUM_PAGES 256 // 1MB virtual address space
#define PAGE_TABLE_SIZE 256
#define MAX_VMS 4

// Page table entry structure
typedef struct {
 uint32_t valid : 1; // Is this page mapped?
 uint32_t read_only : 1; // Read-only page?
 uint32_t user_mode : 1; // User/Kernel page
 uint32_t frame_number : 20; // Physical frame number
 uint32_t offset : 12; // Offset within page (auto)
} PageTableEntry;

// Virtual Machine memory context
typedef struct {
 int vm_id;
 char vm_name[32];
 PageTableEntry page_table[PAGE_TABLE_SIZE];
 uint32_t total_pages_used;
 uint32_t total_memory_mb;
} VMMemoryContext;

// Physical memory (simulated RAM)
typedef struct {
 uint8_t *memory;
 uint32_t total_frames;
 uint32_t free_frames;
 uint8_t *frame_allocated; // Bitmap of allocated frames
} PhysicalMemory;

// Initialize physical memory
PhysicalMemory* init_physical_memory(uint32_t size_mb) {
 PhysicalMemory *phys = malloc(sizeof(PhysicalMemory));
 uint32_t num_frames = (size_mb * 1024 * 1024) / PAGE_SIZE;

 phys->total_frames = num_frames;
 phys->free_frames = num_frames;
 phys->memory = malloc(num_frames * PAGE_SIZE);
 phys->frame_allocated = calloc(num_frames, 1);

 printf("[PHYSMEM] Initialized %u MB physical memory (%u frames)\n", 
 size_mb, num_frames);
 return phys;
}

// Allocate a physical frame for a virtual page
uint32_t allocate_frame(PhysicalMemory *phys) {
 if (phys->free_frames == 0) {
 printf("[PHYSMEM] ERROR: Out of physical memory!\n");
 return -1;
 }

 // Find first free frame (simplified allocation)
 for (uint32_t i = 0; i < phys->total_frames; i++) {
 if (!phys->frame_allocated[i]) {
 phys->frame_allocated[i] = 1;
 phys->free_frames--;
 return i;
 }
 }
 return -1;
}

// Free a physical frame
void free_frame(PhysicalMemory *phys, uint32_t frame_num) {
 if (frame_num < phys->total_frames && phys->frame_allocated[frame_num]) {
 phys->frame_allocated[frame_num] = 0;
 phys->free_frames++;
 }
}

// Initialize VM memory context (creates page table)
VMMemoryContext* create_vm_context(int vm_id, const char *name, 
 uint32_t memory_mb, PhysicalMemory *phys) {
 VMMemoryContext *vm = malloc(sizeof(VMMemoryContext));

 vm->vm_id = vm_id;
 strncpy(vm->vm_name, name, 31);
 vm->vm_name[31] = '\0';
 vm->total_memory_mb = memory_mb;
 vm->total_pages_used = 0;

 // Initialize page table with all pages invalid
 for (int i = 0; i < PAGE_TABLE_SIZE; i++) {
 vm->page_table[i].valid = 0;
 vm->page_table[i].frame_number = 0;
 }

 // Allocate pages on demand (demand paging)
 uint32_t num_pages_needed = (memory_mb * 1024 * 1024) / PAGE_SIZE;
 printf("[VMM] Created VM '%s' with %u MB virtual address space\n", 
 name, memory_mb);

 return vm;
}

// Map a virtual page to a physical frame (page table update)
int map_virtual_page(VMMemoryContext *vm, uint32_t virtual_page, 
 PhysicalMemory *phys, int read_only) {
 if (virtual_page >= PAGE_TABLE_SIZE) {
 printf("[VMM] ERROR: Invalid virtual page %u\n", virtual_page);
 return -1;
 }

 // Allocate physical frame
 uint32_t frame = allocate_frame(phys);
 if (frame == (uint32_t)-1) {
 return -1;
 }

 // Update page table entry
 vm->page_table[virtual_page].valid = 1;
 vm->page_table[virtual_page].frame_number = frame;
 vm->page_table[virtual_page].read_only = read_only;
 vm->page_table[virtual_page].user_mode = 1;
 vm->total_pages_used++;

 printf("[VMM] Mapped virtual page %u -> physical frame %u (VM: %s)\n",
 virtual_page, frame, vm->vm_name);
 return 0;
}

// Translate virtual address to physical address (MMU simulation)
uint32_t translate_address(VMMemoryContext *vm, uint32_t virtual_addr) {
 // Extract page number and offset
 uint32_t page_number = virtual_addr / PAGE_SIZE;
 uint32_t offset = virtual_addr % PAGE_SIZE;

 // Check if page is valid
 if (page_number >= PAGE_TABLE_SIZE || !vm->page_table[page_number].valid) {
 printf("[MMU] PAGE FAULT: Virtual page %u not mapped!\n", page_number);
 return -1;
 }

 // Get physical frame
 uint32_t frame = vm->page_table[page_number].frame_number;
 uint32_t physical_addr = (frame * PAGE_SIZE) + offset;

 return physical_addr;
}

// Demonstrate memory isolation between VMs
void demonstrate_isolation(VMMemoryContext *vm1, VMMemoryContext *vm2, 
 PhysicalMemory *phys) {
 printf("\n=== Demonstrating VM Memory Isolation ===\n");

 // Write to VM1's address space
 uint32_t vm1_vaddr = 0x1000; // Virtual address 4096
 map_virtual_page(vm1, vm1_vaddr / PAGE_SIZE, phys, 0);
 uint32_t vm1_phys = translate_address(vm1, vm1_vaddr);

 // Write to VM2's address space (same virtual address)
 uint32_t vm2_vaddr = 0x1000; // Same virtual address!
 map_virtual_page(vm2, vm2_vaddr / PAGE_SIZE, phys, 0);
 uint32_t vm2_phys = translate_address(vm2, vm2_vaddr);

 printf("VM1 virtual address 0x%04X -> Physical 0x%08X\n", vm1_vaddr, vm1_phys);
 printf("VM2 virtual address 0x%04X -> Physical 0x%08X\n", vm2_vaddr, vm2_phys);

 if (vm1_phys != vm2_phys && vm1_phys != (uint32_t)-1 && vm2_phys != (uint32_t)-1) {
 printf("\n[SUCCESS] VMs are isolated! Same virtual addr maps to different physical frames.\n");
 }
}

int main() {
 printf("=====================================\n");
 printf("Virtual Memory Management Demo\n");
 printf("=====================================\n\n");

 // Initialize 64MB physical memory
 PhysicalMemory *phys_mem = init_physical_memory(64);

 // Create two VM contexts
 VMMemoryContext *vm1 = create_vm_context(1, "WebServer-VM", 16, phys_mem);
 VMMemoryContext *vm2 = create_vm_context(2, "Database-VM", 16, phys_mem);

 printf("\n--- Allocating pages for VM1 ---\n");
 // Simulate allocating some pages
 for (int i = 0; i < 5; i++) {
 map_virtual_page(vm1, i, phys_mem, 0);
 }

 printf("\n--- Allocating pages for VM2 ---\n");
 for (int i = 0; i < 5; i++) {
 map_virtual_page(vm2, i, phys_mem, 0);
 }

 // Demonstrate address translation
 printf("\n--- Address Translation Demo ---\n");
 uint32_t vaddr = 0x3000; // Page 3, offset 0
 uint32_t paddr = translate_address(vm1, vaddr);
 printf("Virtual 0x%X -> Physical 0x%X\n", vaddr, paddr);

 // Demonstrate isolation
 demonstrate_isolation(vm1, vm2, phys_mem);

 // Print memory stats
 printf("\n--- Physical Memory Status ---\n");
 printf("Total frames: %u, Free: %u, Used: %u\n",
 phys_mem->total_frames, 
 phys_mem->free_frames,
 phys_mem->total_frames - phys_mem->free_frames);

 // Cleanup
 free(phys_mem->memory);
 free(phys_mem->frame_allocated);
 free(phys_mem);
 free(vm1);
 free(vm2);

 printf("\n[Demo complete]\n");
 return 0;
}

/*
 * JVM Bytecode and Class Loading Demonstration
 * Shows how Java source code is compiled to bytecode and executed by the JVM
 */

import java.io.*;
import java.lang.reflect.Method;
import java.util.*;

/**
 * Simple class that demonstrates JVM bytecode execution
 * Compile this with: javac JvmDemo.java
 * Run with: java JvmDemo
 */
class JvmDemo {
 private int counter;
 private String name;

 public JvmDemo(String name) {
 this.name = name;
 this.counter = 0;
 }

 public int increment() {
 counter++;
 return counter;
 }

 public int getCounter() {
 return counter;
 }

 public void demonstrateOperations() {
 System.out.println("\n=== JVM Operation Demonstration ===");

 // 1. Stack-based operation (JVM uses operand stack)
 int a = 10;
 int b = 20;
 int c = a + b; // bytecode: iload_0, iload_1, iadd, istore_2
 System.out.println("Stack operation: " + a + " + " + b + " = " + c);

 // 2. Method invocation (different bytecode instructions)
 String result = greet("Student"); // invokevirtual
 System.out.println("Method call result: " + result);

 // 3. Object creation (new bytecode instruction)
 Date date = new Date(); // new instruction
 System.out.println("Object created: " + date.getClass().getName());

 // 4. Array operations
 int[] array = new int[5]; // newarray instruction
 array[0] = 100; // iastore
 int value = array[0]; // iaload
 System.out.println("Array operation: array[0] = " + value);

 // 5. Type casting (checkcast instruction)
 Object obj = "String object";
 if (obj instanceof String) {
 String str = (String) obj; // checkcast
 System.out.println("Type cast: " + str.toUpperCase());
 }
 }

 private String greet(String name) {
 return "Hello, " + name + "! Welcome to CSE";
 }

 public static void main(String[] args) {
 System.out.println("=========================================");
 System.out.println("Java Virtual Machine Demonstration");
 System.out.println("=========================================");

 // Create instance (heap allocation)
 JvmDemo demo = new JvmDemo("university Student");

 // Demonstrate JVM operations
 demo.demonstrateOperations();

 // Show bytecode-related information
 System.out.println("\n=== JVM Runtime Information ===");
 System.out.println("Java Version: " + System.getProperty("java.version"));
 System.out.println("JVM Vendor: " + System.getProperty("java.vendor"));
 System.out.println("JVM Name: " + System.getProperty("java.vm.name"));
 System.out.println("Max Memory: " + Runtime.getRuntime().maxMemory() / (1024*1024) + " MB");
 System.out.println("Free Memory: " + Runtime.getRuntime().freeMemory() / (1024*1024) + " MB");
 System.out.println("Available Processors: " + Runtime.getRuntime().availableProcessors());

 // Demonstrate JIT compilation through repeated execution
 System.out.println("\n=== JIT Compilation Demo ===");
 System.out.println("Running loop 100000 times (JIT compiles hot methods)...");

 long startTime = System.nanoTime();
 int sum = 0;
 for (int i = 0; i < 100000; i++) {
 sum += demo.increment();
 }
 long endTime = System.nanoTime();

 System.out.println("Final counter: " + demo.getCounter());
 System.out.println("Execution time: " + (endTime - startTime) / 1000000.0 + " ms");
 System.out.println("(JIT compiler optimizes frequently called methods)\n");

 // Show class loading information
 System.out.println("=== Class Loader Hierarchy ===");
 ClassLoader loader = JvmDemo.class.getClassLoader();
 System.out.println("This class loaded by: " + loader);
 System.out.println("Parent class loader: " + loader.getParent());

 // List loaded classes (simplified)
 System.out.println("\n=== Package Information ===");
 System.out.println("This class package: " + JvmDemo.class.getPackage());
 System.out.println("Class name: " + JvmDemo.class.getName());
 System.out.println("Simple name: " + JvmDemo.class.getSimpleName());

 System.out.println("\n=========================================");
 System.out.println("Execution complete!");
 System.out.println("=========================================");
 }
}

/**
 * SECOND CLASS: Demonstrates memory management concepts
 * Shows how JVM handles heap, stack, and garbage collection
 */
class JvmMemoryDemo {

 public static void demonstrateMemoryManagement() {
 System.out.println("\n=== JVM Memory Management Demo ===");

 // Show heap usage before allocation
 Runtime rt = Runtime.getRuntime();
 long before = rt.totalMemory() - rt.freeMemory();

 // Create many objects (heap allocation)
 List<String> strings = new ArrayList<>();
 for (int i = 0; i < 1000; i++) {
 strings.add("Object " + i);
 }

 // Show heap usage after allocation
 long after = rt.totalMemory() - rt.freeMemory();
 System.out.println("Memory allocated: " + (after - before) / 1024 + " KB");

 // Clear reference (eligible for GC)
 strings = null;

 // Request garbage collection
 System.out.println("Requesting garbage collection...");
 rt.gc();

 long afterGC = rt.totalMemory() - rt.freeMemory();
 System.out.println("Memory after GC: " + afterGC / 1024 + " KB");
 }

 public static void main(String[] args) {
 demonstrateMemoryManagement();
 }
}
